// Build the WhatsApp order message
function buildWhatsAppMessage(cart, customer) {
  const lines = [];
  lines.push(`*NEW ORDER — BEST HOPE FURNITURE*`);
  lines.push(``);
  lines.push(`*Customer:* ${customer.name}`);
  lines.push(`*Phone:* ${customer.phone}`);
  lines.push(`*Delivery Address:* ${customer.address}`);
  if (customer.notes) lines.push(`*Notes:* ${customer.notes}`);
  lines.push(``);
  lines.push(`*ORDER ITEMS*`);
  cart.forEach((item, i) => {
    lines.push(`${i + 1}. ${item.name} × ${item.qty} — ${fmtNaira(item.price * item.qty)}`);
  });
  lines.push(``);
  const total = cart.reduce((s, i) => s + i.price * i.qty, 0);
  lines.push(`*TOTAL: ${fmtNaira(total)}*`);
  lines.push(``);
  lines.push(`Sent from the BEST HOPE Furniture showroom website.`);
  return encodeURIComponent(lines.join("\n"));
}

